  1	import * as React from 'react';
  2	
  3	import { useTranslation } from 'react-i18next';
  4	
  5	import {
  6	  CheckCircleIcon,
  7	  ExclamationTriangleIcon,
  8	  BuildIcon,
  9	  UploadIcon,
 10	  PendingIcon,
 11	} from '@patternfly/react-icons';
 12	
 13	import { Label, Tooltip } from '@patternfly/react-core';
 14	
 15	const generateLabelWithTooltip = (labelText, color, icon, tooltipText) => {
 16	  return (
 17	    <Tooltip content={tooltipText} position="top" enableFlip>
 18	      <Label isCompact icon={icon} color={color}>
 19	        {labelText}
 20	      </Label>
 21	    </Tooltip>
 22	  );
 23	};
 24	
 25	const getStatusLabel = (obj) => {
 26	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 27	
 28	  const tooltipTexts = {
 29	    Enforced: t('The resource is accepted, programmed, and all policies are enforced.'),
 30	    'Accepted (Not Enforced)': t('The resource is accepted but not all policies are enforced.'),
 31	    Programmed: t('The resource is programmed but not fully enforced.'),
 32	    Conflicted: t('There is a conflict on the resource.'),
 33	    'Resolved Refs': t('All references for the resource have been resolved.'),
 34	    Unknown: t('The status of the resource is unknown.'),
 35	    Creating: t('The resource is being created.'),
 36	    'Overridden (Not Enforced)': t('The resource is overridden and not enforced.'),
 37	    'Conflicted (Not Accepted)': t('There is a conflict and the resource is not accepted.'),
 38	    'TargetNotFound (Not Accepted)': t(
 39	      'The target for the resource was not found and it is not accepted.',
 40	    ),
 41	    'Unknown (Not Accepted)': t('The resource has an unknown status and is not accepted.'),
 42	    'Invalid (Not Accepted)': t('The resource is invalid and not accepted.'),
 43	  };
 44	
 45	  const { kind, status } = obj;
 46	
 47	  const policiesMap = {
 48	    Gateway: [
 49	      'kuadrant.io/DNSPolicyAffected',
 50	      'kuadrant.io/TLSPolicyAffected',
 51	      'kuadrant.io/AuthPolicyAffected',
 52	      'kuadrant.io/RateLimitPolicyAffected',
 53	    ],
 54	    HTTPRoute: ['kuadrant.io/AuthPolicyAffected', 'kuadrant.io/RateLimitPolicyAffected'],
 55	  };
 56	
 57	  const policiesAffected = policiesMap[kind] || [];
 58	
 59	  const hasAllPoliciesEnforced = (conditions) => {
 60	    const relevantPolicies = policiesAffected.filter((policy) =>
 61	      conditions.some((cond) => cond.type === policy),
 62	    );
 63	
 64	    return relevantPolicies.every((policy) =>
 65	      conditions.some((cond) => cond.type === policy && cond.status === 'True'),
 66	    );
 67	  };
 68	
 69	  const hasAnyPolicyError = (conditions) => {
 70	    return policiesAffected.some((policy) =>
 71	      conditions.some((cond) => cond.type === policy && cond.status === 'False'),
 72	    );
 73	  };
 74	
 75	  if (kind === 'Gateway') {
 76	    const conditions = status?.conditions || [];
 77	
 78	    const acceptedCondition = conditions.find(
 79	      (cond) => cond.type === 'Accepted' && cond.status === 'True',
 80	    );
 81	    const programmedCondition = conditions.find(
 82	      (cond) => cond.type === 'Programmed' && cond.status === 'True',
 83	    );
 84	
 85	    if (acceptedCondition && programmedCondition) {
 86	      if (hasAllPoliciesEnforced(conditions) && !hasAnyPolicyError(conditions)) {
 87	        return generateLabelWithTooltip(
 88	          'Enforced',
 89	          'green',
 90	          <CheckCircleIcon />,
 91	          tooltipTexts['Enforced'],
 92	        );
 93	      } else {
 94	        return generateLabelWithTooltip(
 95	          'Accepted (Not Enforced)',
 96	          'purple',
 97	          <UploadIcon />,
 98	          tooltipTexts['Accepted (Not Enforced)'],
 99	        );
100	      }
101	    } else if (programmedCondition) {
102	      return generateLabelWithTooltip(
103	        'Programmed',
104	        'blue',
105	        <CheckCircleIcon />,
106	        tooltipTexts['Programmed'],
107	      );
108	    } else if (conditions.some((cond) => cond.type === 'Conflicted' && cond.status === 'True')) {
109	      return generateLabelWithTooltip(
110	        'Conflicted',
111	        'red',
112	        <ExclamationTriangleIcon />,
113	        tooltipTexts['Conflicted'],
114	      );
115	    } else if (conditions.some((cond) => cond.type === 'ResolvedRefs' && cond.status === 'True')) {
116	      return generateLabelWithTooltip(
117	        'Resolved Refs',
118	        'blue',
119	        <CheckCircleIcon />,
120	        tooltipTexts['Resolved Refs'],
121	      );
122	    } else {
123	      return generateLabelWithTooltip(
124	        'Unknown',
125	        'orange',
126	        <ExclamationTriangleIcon />,
127	        tooltipTexts['Unknown'],
128	      );
129	    }
130	  }
131	
132	  if (policiesAffected.length > 0) {
133	    const parentConditions = status?.parents?.flatMap((parent) => parent.conditions) || [];
134	
135	    const acceptedCondition = parentConditions.find(
136	      (cond) => cond.type === 'Accepted' && cond.status === 'True',
137	    );
138	    const conflictedCondition = parentConditions.find(
139	      (cond) => cond.type === 'Conflicted' && cond.status === 'True',
140	    );
141	    const resolvedRefsCondition = parentConditions.find(
142	      (cond) => cond.type === 'ResolvedRefs' && cond.status === 'True',
143	    );
144	
145	    if (acceptedCondition) {
146	      if (hasAllPoliciesEnforced(parentConditions) && !hasAnyPolicyError(parentConditions)) {
147	        return generateLabelWithTooltip(
148	          'Enforced',
149	          'green',
150	          <CheckCircleIcon />,
151	          tooltipTexts['Enforced'],
152	        );
153	      } else {
154	        return generateLabelWithTooltip(
155	          'Accepted (Not Enforced)',
156	          'purple',
157	          <UploadIcon />,
158	          tooltipTexts['Accepted (Not Enforced)'],
159	        );
160	      }
161	    } else if (conflictedCondition) {
162	      return generateLabelWithTooltip(
163	        'Conflicted',
164	        'red',
165	        <ExclamationTriangleIcon />,
166	        tooltipTexts['Conflicted'],
167	      );
168	    } else if (resolvedRefsCondition) {
169	      return generateLabelWithTooltip(
170	        'Resolved Refs',
171	        'blue',
172	        <CheckCircleIcon />,
173	        tooltipTexts['Resolved Refs'],
174	      );
175	    } else {
176	      return generateLabelWithTooltip(
177	        'Unknown',
178	        'orange',
179	        <ExclamationTriangleIcon />,
180	        tooltipTexts['Unknown'],
181	      );
182	    }
183	  }
184	
185	  const generalConditions = status?.conditions || [];
186	
187	  if (generalConditions.length === 0) {
188	    return generateLabelWithTooltip('Creating', 'cyan', <PendingIcon />, tooltipTexts['Creating']);
189	  }
190	
191	  const enforcedCondition = generalConditions.find(
192	    (cond) => cond.type === 'Enforced' && cond.status === 'True',
193	  );
194	  const acceptedCondition = generalConditions.find(
195	    (cond) => cond.type === 'Accepted' && cond.status === 'True',
196	  );
197	  const acceptedConditionFalse = generalConditions.find(
198	    (cond) => cond.type === 'Accepted' && cond.status === 'False',
199	  );
200	  const overriddenCondition = generalConditions.find(
201	    (cond) => cond.reason === 'Overridden' && cond.status === 'False',
202	  );
203	  const conflictedCondition = generalConditions.find(
204	    (cond) => cond.reason === 'Conflicted' && cond.status === 'False',
205	  );
206	  const targetNotFoundCondition = generalConditions.find(
207	    (cond) => cond.reason === 'TargetNotFound' && cond.status === 'False',
208	  );
209	  const unknownCondition = generalConditions.find(
210	    (cond) => cond.reason === 'Unknown' && cond.status === 'False',
211	  );
212	
213	  if (enforcedCondition) {
214	    return generateLabelWithTooltip(
215	      'Enforced',
216	      'green',
217	      <CheckCircleIcon />,
218	      tooltipTexts['Enforced'],
219	    );
220	  } else if (overriddenCondition) {
221	    return generateLabelWithTooltip(
222	      'Overridden (Not Enforced)',
223	      'grey',
224	      <BuildIcon />,
225	      tooltipTexts['Overridden (Not Enforced)'],
226	    );
227	  } else if (acceptedCondition) {
228	    return generateLabelWithTooltip(
229	      'Accepted (Not Enforced)',
230	      'purple',
231	      <UploadIcon />,
232	      tooltipTexts['Accepted (Not Enforced)'],
233	    );
234	  } else if (conflictedCondition) {
235	    return generateLabelWithTooltip(
236	      'Conflicted (Not Accepted)',
237	      'red',
238	      <ExclamationTriangleIcon />,
239	      tooltipTexts['Conflicted (Not Accepted)'],
240	    );
241	  } else if (targetNotFoundCondition) {
242	    return generateLabelWithTooltip(
243	      'TargetNotFound (Not Accepted)',
244	      'red',
245	      <ExclamationTriangleIcon />,
246	      tooltipTexts['TargetNotFound (Not Accepted)'],
247	    );
248	  } else if (unknownCondition) {
249	    return generateLabelWithTooltip(
250	      'Unknown (Not Accepted)',
251	      'orange',
252	      <ExclamationTriangleIcon />,
253	      tooltipTexts['Unknown (Not Accepted)'],
254	    );
255	  } else if (acceptedConditionFalse) {
256	    return generateLabelWithTooltip(
257	      'Invalid (Not Accepted)',
258	      'red',
259	      <ExclamationTriangleIcon />,
260	      tooltipTexts['Invalid (Not Accepted)'],
261	    );
262	  } else {
263	    return generateLabelWithTooltip(
264	      'Unknown',
265	      'grey',
266	      <ExclamationTriangleIcon />,
267	      tooltipTexts['Unknown'],
268	    );
269	  }
270	};
271	
272	export { getStatusLabel };

